INSERT INTO predmet (id, sifra, naziv, espb, studijski_program_id, katedra_id, kratak_opis) VALUES (1, '13S001', 'Matematika 1', 8, 1, 1, 'Algebra, realne funkcije i diferencijalni račun.');
INSERT INTO sadrzaj_predmeta (predmet_id, cilj, ishodi_ucenja, metode_nastave, teme_kursa) VALUES (1, 'Cilj predmeta Matematika 1 je da student savlada teorijske i praktične osnove neophodne za dalji studij i inženjersku praksu u oblasti koju predmet pokriva.', 'Student je sposoban da primeni ključne koncepte kurseva u projektnim zadacima; analizira probleme i bira odgovarajuće algoritme i alate; dokumentuje rešenja.', 'Predavanja, vežbe, individualni i timski domaći zadaci, laboratorijske vežbe, kolokvijumi i završni ispit. Akcenat na aktivnom učenju i feedback-u.', 'Tok kursa obuhvata osnovne teme iz matematika 1, uključujući pregled literature, rad u razvojnom okruženju i vežbe iz tipskih zadataka iz_ispitne prakse.');
INSERT INTO predmet (id, sifra, naziv, espb, studijski_program_id, katedra_id, kratak_opis) VALUES (2, '13S002', 'Programiranje 1', 8, 1, 1, 'Uvod u algoritme, strukture podataka i Python/C.');
INSERT INTO sadrzaj_predmeta (predmet_id, cilj, ishodi_ucenja, metode_nastave, teme_kursa) VALUES (2, 'Cilj predmeta Programiranje 1 je da student savlada teorijske i praktične osnove neophodne za dalji studij i inženjersku praksu u oblasti koju predmet pokriva.', 'Student je sposoban da primeni ključne koncepte kurseva u projektnim zadacima; analizira probleme i bira odgovarajuće algoritme i alate; dokumentuje rešenja.', 'Predavanja, vežbe, individualni i timski domaći zadaci, laboratorijske vežbe, kolokvijumi i završni ispit. Akcenat na aktivnom učenju i feedback-u.', 'Tok kursa obuhvata osnovne teme iz programiranje 1, uključujući pregled literature, rad u razvojnom okruženju i vežbe iz tipskih zadataka iz_ispitne prakse.');
